enum Command { Add(i64, i64), Mul(i64, i64), Quit }
fn parse(input: &str) -> Command {
    let mut fields = input.split_whitespace();
    match fields.next().unwrap() {
        "add" => Command::Add(fields.next().unwrap().parse().unwrap(), fields.next().unwrap().parse().unwrap()),
        "mul" => Command::Mul(fields.next().unwrap().parse().unwrap(), fields.next().unwrap().parse().unwrap()),
        "quit" => Command::Quit,
        _ => unreachable!(),
    }
}
fn evaluate(command: Command) -> i64 {
    // TODO: replace the catch-all with correct Mul and Quit arms.
    match command {
        Command::Add(left, right) => left + right,
        _ => i64::MIN,
    }
}

